// Define a structure to represent a region
typedef struct Region {
  int x, y, width, height;
  int* pixels;
} Region;

// Function to split a region into four quadrants
void split_region(Region* region) {
  // Calculate quadrant boundaries
  int x_mid = region->x + region->width / 2;
  int y_mid = region->y + region->height / 2;

  // Create four new regions
  Region* quadrants[4];
  for (int i = 0; i < 4; i++) {
    quadrants[i] = malloc(sizeof(Region));
    quadrants[i]->x = region->x + (i % 2) * (region->width / 2);
    quadrants[i]->y = region->y + (i / 2) * (region->height / 2);
    quadrants[i]->width = region->width / 2;
    quadrants[i]->height = region->height / 2;
    quadrants[i]->pixels = malloc(region->width * region->height / 4 * sizeof(int));
  }

  // Assign pixels to quadrants
  for (int i = 0; i < region->width * region->height; i++) {
    int x = i % region->width;
    int y = i / region->width;
    int quadrant_index = (x < x_mid) ? (y < y_mid ? 0 : 1) : (y < y_mid ? 2 : 3);
    quadrants[quadrant_index]->pixels[i / 4] = region->pixels[i];
  }

  // Free original region memory
  free(region->pixels);
  free(region);
}

// Example usage
int main() {
  // Create a sample region
  Region* region = malloc(sizeof(Region));
  region->x = 0;
  region->y = 0;
  region->width = 100;
  region->height = 100;
  region->pixels = malloc(100 * 100 * sizeof(int));

  // Split the region into four quadrants
  split_region(region);

  return 0;
}
